const jd = $('Normalize JD').item.json;
const cv = $('Normalize CV').item.json;
const match = $('Normalize Matcher').item.json;

return [{
  json: {
    // Metadata
    submitted_at: new Date().toISOString(),

    // Candidate info
    candidate_name: cv.candidate_name,
    email: cv.email,

    // Role info
    company: jd.company,
    job_title: jd.job_title,
    job_family: jd.job_family,
    seniority_level: jd.seniority_level,

    // Match results
    match_score: match.match_score,
    experience_fit: match.experience_fit,
    recommendation: match.recommendation,

    // Skills
    matched_skills: match.matched_skills.join(', '),
    missing_must_have: match.missing_must_have.join(', ') || 'None',
    missing_nice_to_have: match.missing_nice_to_have.join(', ') || 'None',
    skills_to_surface: match.skills_to_surface.join(', '),

    // Domain flags
    matched_domain_flags: match.matched_domain_flags.join(', '),
    unmatched_domain_flags: match.unmatched_domain_flags.join(', ') || 'None',

    // Competencies
    matched_competencies: match.matched_competencies.join(', '),
    unmatched_competencies: match.unmatched_competencies.join(', ') || 'None',

    // Qualitative
    strengths: match.strengths.join(' | '),
    gaps: match.gaps.join(' | '),

    // CV improvement outputs
    cv_summary_rewrite: match.cv_summary_rewrite,
    bullet_rewrites: match.bullet_rewrites.join('\n'),
  }
}];

try {
  const raw = $input.item.json.output?.[0]?.content?.[0]?.text;

  if (!raw) {
    throw new Error('Cover letter is empty — check Cover Letter Generator node');
  }

  // text is now a plain string directly
  const text = typeof raw === 'string' ? raw : raw?.cover_letter ?? "";

  if (!text) {
    throw new Error('Cover letter text could not be extracted');
  }

  return [{
    json: {
      cover_letter_text: text
    }
  }];

} catch(e) {
  throw new Error('Cover Letter Normalize failed: ' + e.message);
}
